[{"name_path": "TeamsManagementController", "kind": "Class", "body_location": {"start_line": 59, "end_line": 382}, "body": "@Coded('CTMMG')
@ApiDefault()
@Authorized()
@Controller('teams') // Caution: global team access (@Controller('teams')) is not acceptable except for super admins
export class TeamsManagementController extends BaseController {
  private readonly logger = new Logger(TeamsManagementController.name);

  constructor(
    private readonly teamsService: TeamsService,
    private readonly usersService: UsersService,
    private readonly sessionsService: SessionsService,
    private readonly resourcesService: ResourcesService,
    private readonly playersService: PlayersService,
  ) {
    super();
  }

  static ERROR_CODES = {
    INVALID_ROLE: ErrorInfo.getBuilder('IR', 'invalid_role_for_this_user'),
  };

  get EC() {
    return TeamsManagementController.ERROR_CODES;
  }

  @ApiOperation({
    summary: '[superuser][basic,read] Searches teams (for super admins)',
    description: '',
    tags: ['team'],
  })
  @UseGuards(new SuperAdminAccessGuard('basic', 'read'))
  @CodedMethod('STM')
  @Post('search')
  async searchTeams(
    @Req() req: AppExtendedRequest,
    @Body() dto: TeamSearchDto,
  ) {
    const cbuilder = this.getCodeBuilder();

    const validated = ValidationUtil.validate(teamSearchDtoValidator(), dto);

    const result = await this.teamsService.searchTeams(validated);

    return {
      teams: result.teams,
      total: result.total,
    };
  }

  @ApiOperation({
    summary:
      '[superuser][basic,read] Gets locations of all sessions of all teams',
    description: '',
    tags: ['session'],
  })
  @UseGuards(new SuperAdminAccessGuard('basic', 'read'))
  @CodedMethod('LS')
  @Get('sessions/locations')
  async getAllLocations(
    @Req() req: AppExtendedRequest,
    @Query() dto: LocationSearchDto,
  ) {
    const cbuilder = this.getCodeBuilder();

    const validated = ValidationUtil.validate(
      locationSearchDtoValidator(),
      dto,
    );

    const result = await this.sessionsService.getLocations(validated, {});

    return {
      locations: result.locations,
    };
  }

  @ApiOperation({
    summary: '[superuser][basic,read] Search sessions (for super admins)',
    description: '',
    tags: ['session'],
  })
  @UseGuards(new SuperAdminAccessGuard('basic', 'read'))
  @CodedMethod('SSS')
  @Post('sessions/search')
  async searchSessions(
    @Req() req: AppExtendedRequest,
    @Body() dto: SessionSearchDto,
  ) {
    const cbuilder = this.getCodeBuilder();

    const validated = ValidationUtil.validate(sessionSearchDtoValidator(), dto);

    const result = await this.sessionsService.searchSessions(
      validated,
      {},
      true,
      false,
    );

    return {
      sessions: result.sessions,
      total: result.total,
    };
  }

  @ApiOperation({
    summary: '[superuser][basic,read] Lists resources of all teams',
    description:
      'sample: teamId="11111111-0001-0000-0000-000000000000", sessionId="11111111-0002-0000-0000-000000000000"',
    tags: ['resource'],
  })
  @UseGuards(new SuperAdminAccessGuard('basic', 'read'))
  @CodedMethod('STRSS')
  @Post('resources/search')
  async searchTeamResources(
    @Req() req: AppExtendedRequest,
    @Body() dto: MultiTeamsResourceSearchDto,
  ) {
    const cbuilder = this.getCodeBuilder();
    const { requesterUid, roleChecker } = req.appExtension.auth!;

    const validated = ValidationUtil.validate(
      multiTeamsResourceSearchDtoValidator(),
      dto,
    );

    const { resources, total } =
      await this.resourcesService.searchResourcesForMultiTeams(
        validated,
        false,
      );

    return {
      resources,
      total,
    };
  }

  @ApiOperation({
    summary: '[superuser][basic,read] Search players (for super admins)',
    description: '',
    tags: ['player'],
  })
  @UseGuards(new SuperAdminAccessGuard('basic', 'read'))
  @CodedMethod('SPLY')
  @Post('players/search')
  async searchPlayers(
    @Req() req: AppExtendedRequest,
    @Body() dto: PlayerSearchMultiTeamsDto,
  ) {
    const cbuilder = this.getCodeBuilder();

    const validated = ValidationUtil.validate(
      playerSearchMultiTeamsDtoValidator(),
      dto,
    );

    const result =
      await this.playersService.searchPlayersForMultipleTeams(validated);

    return {
      players: result.players,
      total: result.total,
    };
  }

  @ApiOperation({
    summary: '[superuser][basic,write] Creates a team (for super admins)',
    description: '',
    tags: ['team'],
  })
  @UseGuards(new SuperAdminAccessGuard('basic', 'write'))
  @CodedMethod('CTM')
  @Post()
  async createNewTeam(
    @Req() req: AppExtendedRequest,
    @Body() dto: TeamCreateDto,
  ) {
    const cbuilder = this.getCodeBuilder();
    const { requesterUid } = req.appExtension.auth!;

    const validatedDataBasic = ValidationUtil.validate(
      teamCreateDtoValidatorPreChecking(),
      dto,
    );

    if (validatedDataBasic.createOwnerAccount) {
      const validated = ValidationUtil.validate(
        teamAndUserCreateDtoValidator(),
        dto,
      );

      const { user, team } = await this.usersService.createUserWithTeam(
        validated,
        requesterUid,
        {
          lang:
            req.headers['accept-language'] ??
            req.headers['content-language'] ??
            null,
        },
      );

      return {
        team: team,
        user: user,
      };
    } else {
      const { user, team } =
        await this.teamsService.createTeam(validatedDataBasic);
      return {
        team: team,
        user: user,
      };
    }
  }

  @ApiOperation({
    summary:
      '[superuser][basic,write] Creates a new team plan (for super admins)',
    description: '',
    tags: ['team-plan'],
  })
  @UseGuards(new SuperAdminAccessGuard('basic', 'write'))
  @CodedMethod('CTP')
  @Post(':teamId/team-plans')
  async createTeamPlan(
    @Req() req: AppExtendedRequest,
    @Param('teamId', ParseUUIDPipe) targetTeamId: string,
    @Body() dto: TeamPlanCreateDto,
  ) {
    const cbuilder = this.getCodeBuilder();

    const validated = ValidationUtil.validate(
      teamPlanCreateDtoValidator(),
      dto,
    );

    const result = await this.teamsService.createTeamPlan(
      targetTeamId,
      validated,
    );
    return {
      team: result.team,
    };
  }

  @ApiOperation({
    summary: '[superuser][basic,write] Updates a team plan (for super admins)',
    description:
      'Updatable team plans are `next` and `current`, or `previous` if `current` does not exist. ' +
      'Updating other teamPlans are not permitted.',
    tags: ['team-plan'],
  })
  @UseGuards(new SuperAdminAccessGuard('basic', 'write'))
  @CodedMethod('UTP')
  @Put(':teamId/team-plans/:teamPlanId')
  async updateTeamPlan(
    @Req() req: AppExtendedRequest,
    @Param('teamId', ParseUUIDPipe) targetTeamId: string,
    @Param('teamPlanId', ParseUUIDPipe) targetTeamPlanId: string,
    @Body() dto: TeamPlanUpdateDto,
  ) {
    const cbuilder = this.getCodeBuilder();

    const validated = ValidationUtil.validate(
      teamPlanUpdateDtoValidator(),
      dto,
    );

    const result = await this.teamsService.updateTeamPlan(
      targetTeamId,
      targetTeamPlanId,
      validated,
    );
    return {
      team: result.team,
    };
  }

  @ApiOperation({
    summary:
      '[superuser][basic,write] Deletes a next team plan (for super admins)',
    description: '',
    tags: ['team-plan'],
  })
  @UseGuards(new SuperAdminAccessGuard('basic', 'write'))
  @CodedMethod('DNTP')
  @Delete(':teamId/team-plans/:teamPlanId')
  async deleteNextTeamPlan(
    @Req() req: AppExtendedRequest,
    @Param('teamId', ParseUUIDPipe) targetTeamId: string,
    @Param('teamPlanId', ParseUUIDPipe) targetTeamPlanId: string,
  ) {
    const cbuilder = this.getCodeBuilder();

    const result = await this.teamsService.deleteNextTeamPlan(
      targetTeamId,
      targetTeamPlanId,
    );
    return {
      team: result.team,
    };
  }

  @ApiOperation({
    summary: '[superuser][basic,write] Cancels team deletion and reactivate',
    description: '',
    tags: ['team'],
  })
  @UseGuards(new SuperAdminAccessGuard('basic', 'write'))
  @CodedMethod('RAT')
  @Put(':teamId/activate')
  async reactivateTeam(
    @Req() req: AppExtendedRequest,
    @Param('teamId', ParseUUIDPipe) targetTeamId: string,
  ) {
    const cbuilder = this.getCodeBuilder();

    const result = await this.teamsService.reactivateTeam(targetTeamId);

    return { team: result.team };
