@CodedMethod('SRSS')
async searchResources(
  teamId: string,
  sessionId: string,
  conditions: ResourceSearchDtoValidated,
  constraints: {
    userId?: string;
  },
  csvMode: boolean = false,
): Promise<{
  resources: Resource[];
  total: number;
}> {
  const cbuilder = this.getCodeBuilder();

  const elapsedTimesMillis = {
    check: 0,
    search: 0,
    retrieve: 0,
    tran: 0,
    signed: 0,
  };

  this.logger.log(
    `Perf[resource-search-s]: tid=${teamId}, uid=${constraints.userId}.`,
  );

  const startTime = new Date();

  const tranResult = await this.datasource.manager.transaction(async (t) => {
    // Check the user or team owns the session (Validity of sessionId)
    const searchStartTime = new Date();

    const sessionToCheck = await this.sessionsPersistence.checkSessionAccess(
      t,
      teamId,
      sessionId,
      constraints.userId,
      false,
    );

    if (!sessionToCheck.exists || sessionToCheck.id === null) {
      throw new CodedInvalidArgumentException(
        this.code,
        this.EC.INVALID_SESSION_ID(cbuilder.build()),
      );
    }

    if (constraints.userId && !sessionToCheck.belongsToRequester) {
      throw new CodedForbiddenException(
        this.code,
        this.EC.FORBIDDEN_RESOURCE_ACCESS(cbuilder.build()),
      );
    }

    const checkEndTime = new Date();
    elapsedTimesMillis.check = moment(checkEndTime).diff(
      searchStartTime,
      'milliseconds',
    );

    const { resourceIds, total } =
      await this.resourcesPersistence.searchResources(
        t,
        sessionToCheck.id,
        conditions,
        constraints,
      );

    const searchEndTime = new Date();
    elapsedTimesMillis.search = moment(searchEndTime).diff(
      checkEndTime,
      'milliseconds',
    );

    const resources = await this.resourcesPersistence.getResources(
      t,
      resourceIds,
      { includePositions: !csvMode },
    );

@CodedMethod('SRMT')
async searchResourcesForMultiTeams(
  conditions: MultiTeamsResourceSearchDtoValidated,
  csvMode: boolean = false,
) {
  const tranResult = await this.datasource.manager.transaction(async (t) => {
    const { resourceIds, total } =
      await this.resourcesPersistence.searchResourcesForMultiTeams(
        t,
        conditions,
      );

    const resources = await this.resourcesPersistence.getResources(
      t,
      resourceIds,
      {
        includeTeams: true,
        includePositions: !csvMode,
      },
    );

    return {
      resources,
      total,
    };
  });

  await this.resourcesPersistence.supplySignedUrlToResources(
    tranResult.resources,
    {
      includeImages: true,
      includeVideos: false,
    },
  );

  return {
    resources: tranResult.resources,
    total: tranResult.total,
  };

