@CodedMethod('SPY')
async searchPlayers(
  conditions: PlayerSearchDtoValidated,
  constraints: {
    userId?: string;
    teamId?: string;
  },
) {
  const tranResult = await this.datasource.manager.transaction(async (t) => {
    const { playerIds, total } = await this.playersPersistence.searchPlayers(
      t,
      conditions,
      constraints,
      0.8,
    );

    const players = await this.playersPersistence.getPlayers(
      t,
      playerIds,
      {},
    );

    return {
      players,
      total,
    };
  });

  const players = tranResult.players;

  await this.playersPersistence.supplySignedUrlToPlayers(players);

  return {
    players,
    total: tranResult.total,
  };
}

/**
 * search condition "keyword" is used for matching with levenshtein distance (CREATE EXTENSION fuzzystrmatch;).
 * @param teamId
 * @param conditions
 * @returns
 */
@CodedMethod('SPYMT')
async searchPlayersForMultipleTeams(conditions: PlayerSearchDtoValidated) {
  const tranResult = await this.datasource.manager.transaction(async (t) => {
    const { playerIds, total } = await this.playersPersistence.searchPlayers(
      t,
      conditions,
      {},
      0.8,
    );

    const players = await this.playersPersistence.getPlayers(
      t,
      playerIds,
      {},
    );

    return {
      players,
      total,
    };
  });

  const players = tranResult.players;

  await this.playersPersistence.supplySignedUrlToPlayers(players);

  return {
    players,
    total: tranResult.total,
  };
}

