import { ApiProperty, ApiPropertyOptional } from '@nestjs/swagger';
import z from 'zod';

import { ValidationUtil } from '@/app/common/utils/validation.util';

export class PlayerSearchDto {
  @ApiPropertyOptional({ type: 'string', example: null }) keyword?:
    | string
    | null;
  @ApiPropertyOptional({ type: 'boolean', example: null })
  isKeywordUsedAsFuzzySearch?: boolean | null;
  @ApiPropertyOptional({ type: 'number', example: 0 }) page?: number;
  @ApiPropertyOptional({ type: 'number', example: 10 }) pageSize?: number;
  @ApiPropertyOptional({ type: 'string', example: 'id' }) orderBy?:
    | 'id'
    | 'name'
    | 'created_at';
  @ApiProperty({ type: 'boolean', example: false }) isOrderDesc?: boolean;
}

export const playerSearchDtoValidator = () =>
  z.object({
    keyword: z.string().nullable().optional(),
    isKeywordUsedAsFuzzySearch: z.boolean().nullable().optional(),
    page: ValidationUtil.defaultPage,
    pageSize: ValidationUtil.defaultPageSize,
    orderBy: z.enum(['id', 'name', 'created_at']).optional().default('id'),
    isOrderDesc: z.boolean().optional().default(false),
  });

export type PlayerSearchDtoValidated = z.infer<
  ReturnType<typeof playerSearchDtoValidator>
>;

export class PlayerCreateDto {
  @ApiProperty({ type: 'string', example: null }) name: string;
  @ApiPropertyOptional({ type: 'string', example: null }) note?: string | null;
  @ApiPropertyOptional({ type: 'string', example: 'none' }) throw?:
    | 'none'
    | 'right'
    | 'left';
  @ApiPropertyOptional({ type: 'string', example: 'none' }) stand?:
    | 'none'
    | 'right'
    | 'left'
    | 'both';
  @ApiPropertyOptional({ type: 'string', example: '2000-01-01' })
  birthday?: Date | null;
  @ApiPropertyOptional({ type: 'string' }) imageUrl?: string | null;
}

export class PlayerSearchMultiTeamsDto {
  @ApiPropertyOptional({ type: 'string', example: null }) keyword?:
    | string
    | null;
  @ApiPropertyOptional({ type: 'boolean', example: null })
  isKeywordUsedAsFuzzySearch?: boolean | null;
  @ApiPropertyOptional({ type: 'number', example: 0 }) page?: number;
  @ApiPropertyOptional({ type: 'number', example: 10 }) pageSize?: number;
  @ApiPropertyOptional({ type: 'string', example: 'id' }) orderBy?:
    | 'id'
    | 'name'
    | 'created_at';
  @ApiPropertyOptional({ type: 'boolean', example: false })
  isOrderDesc?: boolean;
  @ApiPropertyOptional({ type: 'string', example: null }) teamIds?:
    | string[]
    | null;
}

export const playerSearchMultiTeamsDtoValidator = () =>
  z.object({
    keyword: z.string().nullable().optional(),
    isKeywordUsedAsFuzzySearch: z.boolean().nullable().optional(),
    page: ValidationUtil.defaultPage,
    pageSize: ValidationUtil.defaultPageSize,
    orderBy: z.enum(['id', 'name', 'created_at']).optional().default('id'),
    isOrderDesc: z.boolean().optional().default(false),

    teamIds: z.array(z.string().uuid()).nullable().optional().default(null),
  });

export type PlayerSearchMultiTeamsDtoValidated = z.infer<
  ReturnType<typeof playerSearchMultiTeamsDtoValidator>
>;

export const playerCreateDtoValidator = () =>
  z.object({
    name: ValidationUtil.defaultPlayerName,
    note: ValidationUtil.defaultPlayerNote.optional(),
    throw: z.enum(['none', 'right', 'left']).default('none'),
    stand: z.enum(['none', 'right', 'left', 'both']).default('none'),
    birthday: z.string().date().nullable().optional(),
    imageUrl: ValidationUtil.defaultImageUrl.optional(),
  });

export type PlayerCreateDtoValidated = z.infer<
  ReturnType<typeof playerCreateDtoValidator>
>;

export class PlayerUpdateDto {
  @ApiPropertyOptional({ type: 'string', example: null }) name?: string;
  @ApiPropertyOptional({ type: 'string', example: null }) note?: string | null;
  @ApiPropertyOptional({ type: 'string', example: 'none' }) throw?:
    | 'none'
    | 'right'
    | 'left';
  @ApiPropertyOptional({ type: 'string', example: 'none' }) stand?:
    | 'none'
    | 'right'
    | 'left'
    | 'both';
  @ApiPropertyOptional({ type: 'string', example: '2000-01-01' })
  birthday?: Date | null;
  @ApiProperty({ type: 'string' }) imageUrl?: string | null;
}

export const playerUpdateDtoValidator = () =>
  z.object({
    name: ValidationUtil.defaultPlayerName.optional(),
    note: ValidationUtil.defaultPlayerNote.optional(),
    throw: z.enum(['none', 'right', 'left']).optional(),
    stand: z.enum(['none', 'right', 'left', 'both']).optional(),
    birthday: z.string().date().nullable().optional(),
    imageUrl: ValidationUtil.defaultImageUrl.optional(),
  });

export type PlayerUpdateDtoValidated = z.infer<
  ReturnType<typeof playerUpdateDtoValidator>
>;

export class PlayerImageUploadDto {}

export const playerImageUploadDtoValidator = () =>
  z.object({
    file: ValidationUtil.defaultImage,
  });

export type PlayerImageUploadDtoValidated = z.infer<
  ReturnType<typeof playerImageUploadDtoValidator>
>;

